// BuilderMapEqual returns true if the provided BuilderMap objects are equal.
func BuilderMapEqual(a, b BuilderMap) bool {
	if (a == nil) != (b == nil) {
		return false
	}
	if len(a) != len(b) {
		return false
	}
	for k, av := range a {
		bv, ok := b[k]
		if !ok || !builderEqual(av, bv) {
			return false
		}
	}
	return true
}

func builderEqual(a, b builder) bool {
	if (a.matchers == nil) != (b.matchers == nil) {
		return false
	}
	if len(a.matchers) != len(b.matchers) {
		return false
	}
	for i, am := range a.matchers {
		if !matcherEqual(am, b.matchers[i]) {
			return false
		}
	}
	return true
}

func matcherEqual(a, b matcher) bool {
	return a.key == b.key && stringSliceEqual(a.names, b.names)
}

func stringSliceEqual(a, b []string) bool {
	if (a == nil) != (b == nil) {
		return false
	}
	if len(a) != len(b) {
		return false
	}
	for i, av := range a {
		if av != b[i] {
			return false
		}
	}
	return true
}

